package org.apache.commons.compress.archivers.tar;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.apache.commons.compress.archivers.tar.steps"
)
public class CucumberTest {
}

package org.apache.commons.compress.archivers.tar.steps;

import io.cucumber.java.en.*;
import org.apache.commons.compress.archivers.tar.TarArchiveEntry;
import org.apache.commons.compress.archivers.tar.TarArchiveOutputStream;
import static org.junit.Assert.*;

import java.io.*;

public class StepDefs {
    private TarArchiveOutputStream tarOutputStream;
    private File tempFile;
    private TarArchiveEntry entry;
    private String content;

    @Given("a TarArchiveOutputStream writing to a file")
    public void a_tar_archive_output_stream_writing_to_a_file() throws IOException {
        tempFile = File.createTempFile("test", ".tar");
        tempFile.deleteOnExit();
        FileOutputStream fileOutputStream = new FileOutputStream(tempFile);
        tarOutputStream = new TarArchiveOutputStream(fileOutputStream);
    }

    @Given("I create a TarArchiveOutputStream")
    public void i_create_a_tar_archive_output_stream() throws IOException {
        // Already handled in the background step
    }

    @Given("I add an archive entry for a file named {string} with content length {int}")
    public void i_add_an_archive_entry_for_a_file_named_with_content_length(String fileName, int contentLength) throws IOException {
        entry = new TarArchiveEntry(fileName);
        entry.setSize(contentLength);
        tarOutputStream.putArchiveEntry(entry);
    }

    @Given("I write the content of the file to the stream")
    public void i_write_the_content_of_the_file_to_the_stream() throws IOException {
        // Create content with specified length
        content = "A".repeat(Math.max(0, (int) entry.getSize()));
        byte[] contentBytes = content.getBytes();
        tarOutputStream.write(contentBytes);
    }

    @Given("I close the archive entry")
    public void i_close_the_archive_entry() throws IOException {
        tarOutputStream.closeArchiveEntry();
    }

    @When("I close the TarArchiveOutputStream")
    public void i_close_the_tar_archive_output_stream() throws IOException {
        tarOutputStream.close();
    }

    @Then("the value returned by getBytesWritten should equal the total size of the output file")
    public void the_value_returned_by_get_bytes_written_should_equal_the_total_size_of_the_output_file() {
        // Compare the bytes written with the actual file size
        long bytesWritten = tarOutputStream.getBytesWritten();
        long actualFileSize = tempFile.length();

        assertEquals("getBytesWritten should equal the actual file size", actualFileSize, bytesWritten);
    }
}

